"""cedarvisit — a tiny visit-log CLI.

Commands: log (add a record) · list · total · filter <category> · top · report.
"""

import argparse
import sys

from cedarvisit import ops, store


def main(argv=None):
    parser = argparse.ArgumentParser(prog="cedarvisit")
    sub = parser.add_subparsers(dest="command", required=True)
    add_p = sub.add_parser("log", help="add a visit record")
    add_p.add_argument("category")
    add_p.add_argument("duration", type=float)
    add_p.add_argument("--note", default="")
    sub.add_parser("list", help="list all records")
    sub.add_parser("total", help="sum the duration field")
    filter_p = sub.add_parser("filter", help="records in one category")
    filter_p.add_argument("category")
    top_p = sub.add_parser("top", help="highest-duration categories")
    top_p.add_argument("--limit", type=int, default=3)
    sub.add_parser("report", help="per-category count and total, plus overall")
    args = parser.parse_args(argv)

    records = store.load_records()
    if args.command == "log":
        ops.add_record(records, args.category, args.duration, args.note)
        store.save_records(records)
        print("recorded.")
    elif args.command == "list":
        for r in records:
            print(f"{r['category']}: {r['duration']} {r['note']}".rstrip())
    elif args.command == "total":
        print(ops.total_duration(records))
    elif args.command == "filter":
        for r in ops.filter_by_category(records, args.category):
            print(f"{r['category']}: {r['duration']}")
    elif args.command == "top":
        for category, subtotal in ops.top_categories(records, args.limit):
            print(f"{category}: {subtotal}")
    elif args.command == "report":
        if not records:
            print("no records.")
        else:
            for category, count, total in ops.category_report(records):
                print(f"{category}: {count} records, {total}")
            print(f"overall: {len(records)} records, {ops.total_duration(records)}")
    return 0


if __name__ == "__main__":
    sys.exit(main())
"""Core operations over visit records."""


def add_record(records, category, duration, note=""):
    """Append a visit record and return it."""
    record = {
        "category": category,
        "duration": float(duration),
        "note": note,
    }
    records.append(record)
    return record


def total_duration(records):
    """Sum the duration field across records."""
    return sum(r["duration"] for r in records)


def filter_by_category(records, category):
    """Return records whose category matches (case-insensitive)."""
    return [r for r in records if r["category"] == category]


def category_report(records):
    """Return ``(category, count, total)`` rows, sorted by total, highest first.

    Ties on total break alphabetically by category, matching
    :func:`top_categories`.
    """
    stats = {}
    for r in records:
        count, total = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, total + r["duration"])
    rows = [(category, count, total) for category, (count, total) in stats.items()]
    return sorted(rows, key=lambda row: (-row[2], row[0]))


def top_categories(records, limit=3):
    """Return the ``limit`` categories with the highest summed duration."""
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["duration"]
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return ranked[:limit]
